from typing import List
from collections import defaultdict

class Solution:
    def check_nodes(self, tree: List[List[int]]) -> bool:
        if not tree:
            return True

        parent_to_child = defaultdict(list)
        for i, node in enumerate(tree):
            for child in node:
                parent_to_child[child].append(i)

        for node in tree:
            if len(node) > 1 or (len(node) == 1 and node[0] not in parent_to_child.keys()):
                return False

        return True

solution = Solution()
# Test the function
print(solution.check_nodes([[1, []], [2, [5]], [3, []], [4, [6]], [5, []], [6, []]]))

