#include <iostream>
#include <vector>

using namespace std;

class Solution {
public:
bool checkNodes(vector<vector<int>>& tree) {
     if (tree.empty())
         return true;

     vector<vector<int>> parent_to_child(tree.size());
     for (int i = 0; i < tree.size(); i++)
         for (int child : tree[i])
             parent_to_child[child].push_back(i);

     for (int i = 0; i < tree.size(); i++) {
         if (tree[i].size() > 1 || (tree[i].size() == 1 && tree[i][0] >= tree.size()))
             return false;
     }

     return true;
}
};

int main() {
    Solution solution;
    // Test the function
